{
  "version": "Notebook/1.0",
  "items": [
    {
      "type": 1,
      "content": {
        "json": "## SmartScreen Web Threats\r\n\r\nHunt for users browsing to malicious, phishing, tech-scam, untrusted, custom-blocked, or **risky non-business category** sites (Adult, Gambling, Dating, Gaming, Streaming) surfaced by Microsoft Defender SmartScreen and Network Protection (Web Content Filtering).\r\n\r\nUse the **Time Range**, **User (UPN)**, **Device**, and **URL contains** filters to scope. Tabs further narrow the threat category. Start with *Top Users / Domains* for triage, then pivot into *Risky User Correlation* to find users that crossed from non-business browsing into malicious activity."
      },
      "name": "header"
    },
    {
      "type": 9,
      "content": {
        "version": "KqlParameterItem/1.0",
        "parameters": [
          {
            "id": "6cba59cc-7211-42de-ade8-13f364ee4107",
            "version": "KqlParameterItem/1.0",
            "name": "TimePicker",
            "label": "Time Range",
            "type": 4,
            "isRequired": true,
            "typeSettings": {
              "selectableValues": [
                { "durationMs": 1800000 },
                { "durationMs": 3600000 },
                { "durationMs": 14400000 },
                { "durationMs": 43200000 },
                { "durationMs": 86400000 },
                { "durationMs": 259200000 },
                { "durationMs": 604800000 },
                { "durationMs": 1209600000 },
                { "durationMs": 2592000000 },
                { "durationMs": 5184000000 },
                { "durationMs": 7776000000 }
              ],
              "allowCustom": true
            },
            "timeContext": { "durationMs": 86400000 },
            "value": { "durationMs": 2592000000 }
          },
          {
            "id": "f1a1b8e1-1111-4111-aaaa-111111111111",
            "version": "KqlParameterItem/1.0",
            "name": "UserUPN",
            "label": "User UPN (use * for all, supports partial match)",
            "type": 1,
            "value": "*"
          },
          {
            "id": "f1a1b8e1-2222-4222-aaaa-222222222222",
            "version": "KqlParameterItem/1.0",
            "name": "DeviceName",
            "label": "Device (use * for all, supports partial match)",
            "type": 1,
            "value": "*"
          },
          {
            "id": "f1a1b8e1-3333-4333-aaaa-333333333333",
            "version": "KqlParameterItem/1.0",
            "name": "UrlContains",
            "label": "URL contains (press Enter to apply, e.g. bet365)",
            "type": 1,
            "isRequired": false,
            "value": ""
          }
        ],
        "style": "pills",
        "queryType": 0,
        "resourceType": "microsoft.operationalinsights/workspaces"
      },
      "name": "parameters - 1"
    },
    {
      "type": 11,
      "content": {
        "version": "LinkItem/1.0",
        "style": "tabs",
        "links": [
          { "id": "tab-overview",    "cellValue": "Tab", "linkTarget": "parameter", "linkLabel": "Top Users / Domains",       "subTarget": "Overview",  "style": "link" },
          { "id": "tab-correlate",   "cellValue": "Tab", "linkTarget": "parameter", "linkLabel": "Risky User Correlation",    "subTarget": "Correlate", "style": "link" },
          { "id": "tab-all",         "cellValue": "Tab", "linkTarget": "parameter", "linkLabel": "All Categories (URL+Files)","subTarget": "First",     "style": "link" },
          { "id": "tab-webcat",      "cellValue": "Tab", "linkTarget": "parameter", "linkLabel": "Web Content Filter (Category)", "subTarget": "WebCat", "style": "link" },
          { "id": "tab-files",       "cellValue": "Tab", "linkTarget": "parameter", "linkLabel": "Files (SmartScreenApp)",    "subTarget": "Eighth",    "style": "link" },
          { "id": "tab-smartscreen", "cellValue": "Tab", "linkTarget": "parameter", "linkLabel": "SmartScreen URL Categories", "subTarget": "URL",       "style": "link" },
          { "id": "tab-overrides",   "cellValue": "Tab", "linkTarget": "parameter", "linkLabel": "User Overrides & Bypasses",  "subTarget": "Override",  "style": "link" }
        ]
      },
      "name": "links - 2"
    },

    {
      "type": 12,
      "content": {
        "version": "NotebookGroup/1.0",
        "groupType": "editable",
        "title": "Top Users / Domains",
        "items": [
          {
            "type": 1,
            "content": { "json": "Top 25 users, devices, domains, and SmartScreen/Web-Content categories across the selected scope. Click a row to view the **same scope** filtered in the category tabs." },
            "name": "ovw-text"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "DeviceEvents\r\n| where ActionType in (\"SmartScreenAppWarning\",\"SmartScreenUrlWarning\",\"ExploitGuardNetworkProtectionBlocked\",\"ExploitGuardNetworkProtectionAudited\")\r\n| where \"{DeviceName}\" == \"*\" or DeviceName has \"{DeviceName}\"\r\n| where \"{UserUPN}\" == \"*\" or InitiatingProcessAccountUpn has \"{UserUPN}\"\r\n| where \"{UrlContains}\" == \"\" or RemoteUrl has \"{UrlContains}\"\r\n| extend P = parse_json(AdditionalFields)\r\n| extend Category    = tostring(P.Experience),\r\n         WebCategory = tostring(P.ResponseCategory)\r\n| extend Bucket = case(\r\n     ActionType in (\"ExploitGuardNetworkProtectionBlocked\",\"ExploitGuardNetworkProtectionAudited\"), strcat(\"WebContent: \", iff(isempty(WebCategory),\"(uncategorized)\",WebCategory)),\r\n     isnotempty(Category), Category,\r\n     ActionType)\r\n| summarize Events = count() by Bucket\r\n| top 20 by Events desc\r\n| render barchart",
              "size": 1,
              "title": "Events by Category",
              "timeContextFromParameter": "TimePicker",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces"
            },
            "customWidth": "50",
            "name": "ovw-category"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "DeviceEvents\r\n| where ActionType in (\"SmartScreenAppWarning\",\"SmartScreenUrlWarning\",\"ExploitGuardNetworkProtectionBlocked\",\"ExploitGuardNetworkProtectionAudited\")\r\n| where \"{DeviceName}\" == \"*\" or DeviceName has \"{DeviceName}\"\r\n| where \"{UserUPN}\" == \"*\" or InitiatingProcessAccountUpn has \"{UserUPN}\"\r\n| where \"{UrlContains}\" == \"\" or RemoteUrl has \"{UrlContains}\"\r\n| extend Domain = tolower(tostring(parse_url(RemoteUrl).Host))\r\n| where isnotempty(Domain)\r\n| summarize Hits = count(), Users = dcount(InitiatingProcessAccountUpn), Devices = dcount(DeviceName) by Domain\r\n| top 25 by Hits desc",
              "size": 1,
              "title": "Top 25 Domains",
              "timeContextFromParameter": "TimePicker",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "gridSettings": { "rowLimit": 25 }
            },
            "customWidth": "50",
            "name": "ovw-domain"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "DeviceEvents\r\n| where ActionType in (\"SmartScreenAppWarning\",\"SmartScreenUrlWarning\",\"ExploitGuardNetworkProtectionBlocked\",\"ExploitGuardNetworkProtectionAudited\")\r\n| where \"{DeviceName}\" == \"*\" or DeviceName has \"{DeviceName}\"\r\n| where \"{UserUPN}\" == \"*\" or InitiatingProcessAccountUpn has \"{UserUPN}\"\r\n| where \"{UrlContains}\" == \"\" or RemoteUrl has \"{UrlContains}\"\r\n| extend P = parse_json(AdditionalFields)\r\n| extend Category = tostring(P.Experience), WebCategory = tostring(P.ResponseCategory)\r\n| summarize Hits = count(),\r\n            Devices = dcount(DeviceName),\r\n            Domains = dcount(tostring(parse_url(RemoteUrl).Host)),\r\n            MaliciousHits = countif(Category in (\"Malicious\",\"Phishing\",\"TechScam\")),\r\n            RiskyHits     = countif(WebCategory has_any (\"Adult\",\"Gambling\",\"Dating\",\"Gaming\",\"Streaming\")),\r\n            LastSeen = max(TimeGenerated)\r\n         by User = InitiatingProcessAccountUpn\r\n| where isnotempty(User)\r\n| top 25 by Hits desc",
              "size": 1,
              "title": "Top 25 Users (with Malicious & Risky counts)",
              "timeContextFromParameter": "TimePicker",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "gridSettings": {
                "rowLimit": 25,
                "formatters": [
                  { "columnMatch": "MaliciousHits", "formatter": 8, "formatOptions": { "palette": "redBright" } },
                  { "columnMatch": "RiskyHits",     "formatter": 8, "formatOptions": { "palette": "orange" } },
                  { "columnMatch": "Hits",          "formatter": 4, "formatOptions": { "palette": "blue" } }
                ]
              }
            },
            "name": "ovw-users"
          }
        ]
      },
      "conditionalVisibility": { "parameterName": "Tab", "comparison": "isEqualTo", "value": "Overview" },
      "name": "GroupOverview"
    },

    {
      "type": 12,
      "content": {
        "version": "NotebookGroup/1.0",
        "groupType": "editable",
        "title": "Risky User Correlation",
        "items": [
          {
            "type": 1,
            "content": { "json": "Users who triggered **both** risky non-business category events (Adult, Gambling, Dating, Gaming, Streaming) **and** SmartScreen Malicious / Phishing / TechScam events in the selected window. These are prime candidates for SOC follow-up: a browsing path that started in a low-reputation category and ended in confirmed malicious destinations." },
            "name": "corr-text"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "let base =\r\nDeviceEvents\r\n| where ActionType in (\"SmartScreenAppWarning\",\"SmartScreenUrlWarning\",\"ExploitGuardNetworkProtectionBlocked\",\"ExploitGuardNetworkProtectionAudited\")\r\n| where \"{DeviceName}\" == \"*\" or DeviceName has \"{DeviceName}\"\r\n| where \"{UserUPN}\" == \"*\" or InitiatingProcessAccountUpn has \"{UserUPN}\"\r\n| where \"{UrlContains}\" == \"\" or RemoteUrl has \"{UrlContains}\"\r\n| extend P = parse_json(AdditionalFields)\r\n| extend Category = tostring(P.Experience), WebCategory = tostring(P.ResponseCategory)\r\n| extend IsRisky     = WebCategory has_any (\"Adult\",\"Gambling\",\"Dating\",\"Gaming\",\"Streaming\"),\r\n         IsMalicious = Category in (\"Malicious\",\"Phishing\",\"TechScam\");\r\nbase\r\n| summarize\r\n    RiskyHits      = countif(IsRisky),\r\n    MaliciousHits  = countif(IsMalicious),\r\n    FirstRisky     = minif(TimeGenerated, IsRisky),\r\n    LastRisky      = maxif(TimeGenerated, IsRisky),\r\n    FirstMalicious = minif(TimeGenerated, IsMalicious),\r\n    LastMalicious  = maxif(TimeGenerated, IsMalicious),\r\n    Devices        = make_set(DeviceName, 10),\r\n    SampleRiskyUrls     = make_set_if(RemoteUrl, IsRisky, 5),\r\n    SampleMaliciousUrls = make_set_if(RemoteUrl, IsMalicious, 5)\r\n  by User = InitiatingProcessAccountUpn\r\n| where isnotempty(User) and RiskyHits > 0 and MaliciousHits > 0\r\n| extend MinutesRiskyToMalicious = iff(isnotempty(FirstMalicious) and isnotempty(FirstRisky), datetime_diff('minute', FirstMalicious, FirstRisky), int(null))\r\n| order by MaliciousHits desc, RiskyHits desc",
              "size": 2,
              "title": "Users with Risky+Malicious activity",
              "timeContextFromParameter": "TimePicker",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "gridSettings": {
                "rowLimit": 200,
                "formatters": [
                  { "columnMatch": "MaliciousHits", "formatter": 8, "formatOptions": { "palette": "redBright" } },
                  { "columnMatch": "RiskyHits",     "formatter": 8, "formatOptions": { "palette": "orange" } }
                ]
              }
            },
            "name": "corr-grid"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "DeviceEvents\r\n| where ActionType in (\"SmartScreenAppWarning\",\"SmartScreenUrlWarning\",\"ExploitGuardNetworkProtectionBlocked\",\"ExploitGuardNetworkProtectionAudited\")\r\n| where \"{DeviceName}\" == \"*\" or DeviceName has \"{DeviceName}\"\r\n| where \"{UserUPN}\" == \"*\" or InitiatingProcessAccountUpn has \"{UserUPN}\"\r\n| where \"{UrlContains}\" == \"\" or RemoteUrl has \"{UrlContains}\"\r\n| extend P = parse_json(AdditionalFields)\r\n| extend Category = tostring(P.Experience), WebCategory = tostring(P.ResponseCategory)\r\n| extend Severity = case(\r\n     Category in (\"Malicious\",\"Phishing\",\"TechScam\"), \"High\",\r\n     WebCategory has_any (\"Adult\",\"Gambling\",\"Dating\",\"Gaming\",\"Streaming\"), \"Medium\",\r\n     Category in (\"Untrusted\",\"CustomBlockList\",\"CustomPolicy\"), \"Low\",\r\n     \"Info\")\r\n| project TimeGenerated, User = InitiatingProcessAccountUpn, DeviceName, Severity, Category, WebCategory, ActionType, RemoteUrl, FileName, InitiatingProcessFileName\r\n| order by TimeGenerated desc",
              "size": 2,
              "title": "Full event timeline (filtered)",
              "timeContextFromParameter": "TimePicker",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "gridSettings": {
                "rowLimit": 2000,
                "formatters": [
                  { "columnMatch": "Severity", "formatter": 11, "formatOptions": {
                      "thresholdsOptions": "icons",
                      "thresholdsGrid": [
                        { "operator": "==", "thresholdValue": "High",   "representation": "Critical", "text": "{0}{1}" },
                        { "operator": "==", "thresholdValue": "Medium", "representation": "2",        "text": "{0}{1}" },
                        { "operator": "==", "thresholdValue": "Low",    "representation": "3",        "text": "{0}{1}" },
                        { "operator": "Default",                        "representation": "Info",     "text": "{0}{1}" }
                      ]
                  }}
                ]
              }
            },
            "name": "corr-timeline"
          }
        ]
      },
      "conditionalVisibility": { "parameterName": "Tab", "comparison": "isEqualTo", "value": "Correlate" },
      "name": "GroupCorrelate"
    },

    {
      "type": 12,
      "content": {
        "version": "NotebookGroup/1.0",
        "groupType": "editable",
        "title": "All Categories",
        "items": [
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "DeviceEvents\r\n| where ActionType in (\"SmartScreenAppWarning\",\"SmartScreenUrlWarning\")\r\n| where \"{DeviceName}\" == \"*\" or DeviceName has \"{DeviceName}\"\r\n| where \"{UserUPN}\" == \"*\" or InitiatingProcessAccountUpn has \"{UserUPN}\"\r\n| where \"{UrlContains}\" == \"\" or RemoteUrl has \"{UrlContains}\"\r\n| extend ParsedFields = parse_json(AdditionalFields)\r\n| extend Category = tostring(ParsedFields.Experience)\r\n| where isnotempty(Category)\r\n| summarize count() by Category, bin(TimeGenerated, 1h)",
              "size": 2,
              "timeContextFromParameter": "TimePicker",
              "timeBrushParameterName": "TimeBrush",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "timechart",
              "gridSettings": { "rowLimit": 1500 }
            },
            "name": "all-chart"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "DeviceEvents\r\n| where ActionType in (\"SmartScreenAppWarning\",\"SmartScreenUrlWarning\")\r\n| where \"{DeviceName}\" == \"*\" or DeviceName has \"{DeviceName}\"\r\n| where \"{UserUPN}\" == \"*\" or InitiatingProcessAccountUpn has \"{UserUPN}\"\r\n| where \"{UrlContains}\" == \"\" or RemoteUrl has \"{UrlContains}\"\r\n| extend ParsedFields = parse_json(AdditionalFields)\r\n| extend Category = tostring(ParsedFields.Experience)\r\n| where isnotempty(Category)\r\n| project TimeGenerated, DeviceName, User = InitiatingProcessAccountUpn, FileName, BlockedUrl = RemoteUrl, Category, ActionType, InitiatingProcessFileName\r\n| sort by TimeGenerated desc",
              "size": 2,
              "timeContextFromParameter": "TimeBrush",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "gridSettings": { "rowLimit": 3000 }
            },
            "name": "all-grid"
          }
        ]
      },
      "conditionalVisibility": { "parameterName": "Tab", "comparison": "isEqualTo", "value": "First" },
      "name": "Group1"
    },

    {
      "type": 12,
      "content": {
        "version": "NotebookGroup/1.0",
        "groupType": "editable",
        "title": "Web Content Filter (Category)",
        "items": [
          {
            "type": 1,
            "content": { "json": "Microsoft Defender **Web Content Filtering** categorizes browsing destinations. This tab covers **all three policy outcomes**: **Blocked** and **Audited** events from `DeviceEvents` (`ExploitGuardNetworkProtection*`), plus **Allowed** traffic from `DeviceNetworkEvents` — the only source that surfaces Allow-mode WCF activity in advanced hunting. Use the **Policy outcome** selector (*Audited* / *Blocked* / *Allowed* / *All*) and the **Web category** selector (populated dynamically from your data, plus an *All* option) to drill into any single category — important at scale where overview grids can drop low-volume categories. A built-in classifier maps destination hosts to **Adult content**, **Gambling**, **Dating**, **Gaming**, and **Streaming media** when no `ResponseCategory` is present (e.g. Allow-mode policies)." },
            "name": "wc-text"
          },
          {
            "type": 9,
            "content": {
              "version": "KqlParameterItem/1.0",
              "parameters": [
                {
                  "id": "p-wc-policy",
                  "version": "KqlParameterItem/1.0",
                  "name": "PolicyFilter",
                  "label": "Policy outcome",
                  "type": 2,
                  "isRequired": true,
                  "typeSettings": { "showDefault": false },
                  "jsonData": "[{\"value\":\"All\",\"label\":\"All\"},{\"value\":\"Audited\",\"label\":\"Audited\",\"selected\":true},{\"value\":\"Blocked\",\"label\":\"Blocked\"},{\"value\":\"Allowed\",\"label\":\"Allowed\"}]",
                  "value": "Audited"
                },
                {
                  "id": "p-wc-cat",
                  "version": "KqlParameterItem/1.0",
                  "name": "WebCategoryFilter",
                  "label": "Web category",
                  "type": 2,
                  "isRequired": true,
                  "typeSettings": { "showDefault": false },
                  "query": "let classify = (h:string){case(h has_any (\"xvideos\",\"xnxx\",\"pornhub\",\"redtube\",\"xhamster\",\"chaturbate\",\"livejasmin\",\"onlyfans\",\"brazzers\",\"youporn\",\"spankbang\",\"stripchat\",\"cam4\",\"myfreecams\",\"tnaflix\",\"camsoda\",\"xvideos-cdn\",\"xnxx-cdn\"),\"Adult content\",h has_any (\"bet365\",\"betway\",\"draftkings\",\"fanduel\",\"pokerstars\",\"ladbrokes\",\"888casino\",\"bovada\",\"unibet\",\"bwin\",\"betmgm\",\"stake.com\",\"casino\",\"sportsbet\"),\"Gambling\",h has_any (\"tinder\",\"bumble\",\"match.com\",\"okcupid\",\"hinge\",\"plentyoffish\",\"ashleymadison\",\"grindr\",\"badoo\",\"eharmony\",\"zoosk\"),\"Dating\",h has_any (\"steamcommunity\",\"steampowered\",\"epicgames\",\"battle.net\",\"ubisoft\",\"roblox\",\"minecraft\",\"twitch\",\"gamespot\",\"kotaku\"),\"Gaming\",h has_any (\"netflix\",\"hulu\",\"disneyplus\",\"primevideo\",\"spotify\",\"pandora\",\"soundcloud\",\"tiktok\",\"crunchyroll\",\"hbomax\",\"peacocktv\",\"paramountplus\"),\"Streaming media\",\"\")};\r\nlet net = DeviceNetworkEvents\r\n| extend Host = tolower(tostring(parse_url(RemoteUrl).Host))\r\n| where isnotempty(Host)\r\n| extend WebCategory = classify(Host)\r\n| where isnotempty(WebCategory)\r\n| distinct WebCategory;\r\nlet de = DeviceEvents\r\n| where ActionType in (\"ExploitGuardNetworkProtectionBlocked\",\"ExploitGuardNetworkProtectionAudited\")\r\n| extend WebCategory = tostring(parse_json(AdditionalFields).ResponseCategory)\r\n| where isnotempty(WebCategory)\r\n| distinct WebCategory;\r\nunion (print WebCategory=\"All\"), net, de\r\n| distinct WebCategory\r\n| order by iff(WebCategory==\"All\",0,1) asc, WebCategory asc",
                  "timeContextFromParameter": "TimePicker",
                  "queryType": 0,
                  "resourceType": "microsoft.operationalinsights/workspaces",
                  "value": "All"
                }
              ],
              "style": "pills"
            },
            "name": "wc-policy"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "let pf = \"{PolicyFilter}\";\r\nlet wcat = \"{WebCategoryFilter}\";\r\nlet classify = (h:string){case(h has_any (\"xvideos\",\"xnxx\",\"pornhub\",\"redtube\",\"xhamster\",\"chaturbate\",\"livejasmin\",\"onlyfans\",\"brazzers\",\"youporn\",\"spankbang\",\"stripchat\",\"cam4\",\"myfreecams\",\"tnaflix\",\"camsoda\",\"xvideos-cdn\",\"xnxx-cdn\"),\"Adult content\",h has_any (\"bet365\",\"betway\",\"draftkings\",\"fanduel\",\"pokerstars\",\"ladbrokes\",\"888casino\",\"bovada\",\"unibet\",\"bwin\",\"betmgm\",\"stake.com\",\"casino\",\"sportsbet\"),\"Gambling\",h has_any (\"tinder\",\"bumble\",\"match.com\",\"okcupid\",\"hinge\",\"plentyoffish\",\"ashleymadison\",\"grindr\",\"badoo\",\"eharmony\",\"zoosk\"),\"Dating\",h has_any (\"steamcommunity\",\"steampowered\",\"epicgames\",\"battle.net\",\"ubisoft\",\"roblox\",\"minecraft\",\"twitch\",\"gamespot\",\"kotaku\"),\"Gaming\",h has_any (\"netflix\",\"hulu\",\"disneyplus\",\"primevideo\",\"spotify\",\"pandora\",\"soundcloud\",\"tiktok\",\"crunchyroll\",\"hbomax\",\"peacocktv\",\"paramountplus\"),\"Streaming media\",\"\")};\r\nlet netAllowed = DeviceNetworkEvents\r\n| where \"{DeviceName}\" == \"*\" or DeviceName has \"{DeviceName}\"\r\n| where \"{UserUPN}\" == \"*\" or InitiatingProcessAccountUpn has \"{UserUPN}\"\r\n| where \"{UrlContains}\" == \"\" or RemoteUrl has \"{UrlContains}\"\r\n| extend Host = tolower(tostring(parse_url(RemoteUrl).Host))\r\n| where isnotempty(Host)\r\n| extend WebCategory = classify(Host), PolicyAction = \"Allowed\"\r\n| where isnotempty(WebCategory);\r\nlet dePolicy = DeviceEvents\r\n| where ActionType in (\"ExploitGuardNetworkProtectionBlocked\",\"ExploitGuardNetworkProtectionAudited\")\r\n| where \"{DeviceName}\" == \"*\" or DeviceName has \"{DeviceName}\"\r\n| where \"{UserUPN}\" == \"*\" or InitiatingProcessAccountUpn has \"{UserUPN}\"\r\n| where \"{UrlContains}\" == \"\" or RemoteUrl has \"{UrlContains}\"\r\n| extend P = parse_json(AdditionalFields)\r\n| extend Host = tolower(tostring(parse_url(RemoteUrl).Host))\r\n| extend ResponseCat = tostring(P.ResponseCategory)\r\n| extend WebCategory = iff(isempty(ResponseCat), classify(Host), ResponseCat)\r\n| extend PolicyAction = iff(ActionType == \"ExploitGuardNetworkProtectionBlocked\",\"Blocked\",\"Audited\")\r\n| where isnotempty(WebCategory);\r\nunion netAllowed, dePolicy\r\n| where pf == \"All\" or PolicyAction == pf\r\n| where wcat == \"All\" or WebCategory == wcat\r\n| summarize Hits = count() by WebCategory, bin(TimeGenerated, 1h)",
              "size": 0,
              "title": "Web Content Filter — events by Category (filtered by Policy outcome)",
              "timeContextFromParameter": "TimePicker",
              "timeBrushParameterName": "TimeBrushWC",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "timechart"
            },
            "name": "wc-chart"
          },
          {
            "type": 3,
